  1	import * as React from 'react';
  2	import {
  3	  Flex,
  4	  FlexItem,
  5	  TextInputTypes,
  6	  Button,
  7	  ButtonVariant,
  8	  ButtonType,
  9	  Tooltip,
 10	} from '@patternfly/react-core';
 11	import { GripVerticalIcon } from '@patternfly/react-icons/dist/esm/icons/grip-vertical-icon';
 12	import { MinusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/minus-circle-icon';
 13	import { useTranslation } from 'react-i18next';
 14	import {
 15	  TextColumnItemProps,
 16	  TextColumnFieldChildParameterProps,
 17	  MergeNewValueUtil,
 18	} from './text-column-types';
 19	import InputField from '../pipelines-details/multi-column-field/InputField';
 20	
 21	export type TextColumnItemContentProps = TextColumnItemProps & {
 22	  previewDropRef: (node) => void | null;
 23	  dragRef: (node) => void | null;
 24	  opacity: number;
 25	};
 26	
 27	const DEFAULT_CHILDREN = (
 28	  props: TextColumnFieldChildParameterProps,
 29	  mergeNewValue: MergeNewValueUtil,
 30	) => {
 31	  const { name, onChange, ...otherProps } = props;
 32	
 33	  return (
 34	    <InputField
 35	      {...otherProps}
 36	      name={name}
 37	      type={TextInputTypes.text}
 38	      onChange={(e) => {
 39	        if (onChange) {
 40	          const values = mergeNewValue(e.target.value);
 41	          onChange(values);
 42	        }
 43	      }}
 44	    />
 45	  );
 46	};
 47	
 48	const TextColumnItemContent: React.FC<TextColumnItemContentProps> = ({
 49	  name,
 50	  dndEnabled,
 51	  children = DEFAULT_CHILDREN,
 52	  idx,
 53	  isReadOnly,
 54	  placeholder,
 55	  onChange,
 56	  arrayHelpers,
 57	  rowValues,
 58	  disableDeleteRow,
 59	  tooltipDeleteRow,
 60	  previewDropRef,
 61	  dragRef,
 62	  opacity,
 63	}) => {
 64	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 65	
 66	  const mergeNewValue: MergeNewValueUtil = (newValue) => {
 67	    const values: string[] = [...rowValues];
 68	    values[idx] = newValue;
 69	
 70	    return values;
 71	  };
 72	
 73	  return (
 74	    <div ref={previewDropRef} style={{ opacity }}>
 75	      <Flex
 76	        alignItems={{ default: 'alignItemsFlexStart' }}
 77	        style={{ marginBottom: 'var(--pf-t--global--spacer--200)' }}
 78	      >
 79	        {dndEnabled && (
 80	          <FlexItem style={{ cursor: 'move' }}>
 81	            <div ref={dragRef}>
 82	              <GripVerticalIcon />
 83	            </div>
 84	          </FlexItem>
 85	        )}
 86	        <FlexItem grow={{ default: 'grow' }}>
 87	          {children(
 88	            { name: `${name}.${idx}`, isReadOnly, placeholder, onChange },
 89	            mergeNewValue,
 90	          )}
 91	        </FlexItem>
 92	        {!isReadOnly && (
 93	          <FlexItem>
 94	            <Tooltip
 95	              content={
 96	                tooltipDeleteRow || t('plugin__pipelines-console-plugin~Remove')
 97	              }
 98	            >
 99	              <Button
100	                aria-label={
101	                  tooltipDeleteRow ||
102	                  t('plugin__pipelines-console-plugin~Remove')
103	                }
104	                variant={ButtonVariant.plain}
105	                type={ButtonType.button}
106	                isInline
107	                isDisabled={disableDeleteRow}
108	                onClick={() => {
109	                  arrayHelpers.remove(idx);
110	                  if (onChange) {
111	                    const values = [...rowValues];
112	                    values.splice(idx, 1);
113	                    onChange(values);
114	                  }
115	                }}
116	              >
117	                <MinusCircleIcon />
118	              </Button>
119	            </Tooltip>
120	          </FlexItem>
121	        )}
122	      </Flex>
123	    </div>
124	  );
125	};
126	
127	export default TextColumnItemContent;

